import struct
import time
from dataclasses import dataclass, field
from enum import IntEnum
from typing import List, Optional, Tuple


class MessageType(IntEnum):
    ADD = 0x01
    MODIFY = 0x02
    CANCEL = 0x03
    EXECUTE = 0x04


class Side(IntEnum):
    BID = 0x00
    ASK = 0x01


class FixedPoint:
    SCALE = 10000
    __slots__ = ('_value',)

    def __init__(self, int_value: int):
        if not isinstance(int_value, int):
            raise TypeError(f"FixedPoint requires int, got {type(int_value).__name__}")
        self._value = int_value

    @classmethod
    def from_dollars(cls, dollars: int, cents: int = 0, sub_cents: int = 0) -> 'FixedPoint':
        return cls(dollars * cls.SCALE + cents * 100 + sub_cents)

    @property
    def value(self) -> int:
        return self._value

    def to_float(self) -> float:
        return self._value / self.SCALE

    def __add__(self, other): return FixedPoint(self._value + other._value)
    def __sub__(self, other): return FixedPoint(self._value - other._value)
    def __mul__(self, scalar: int):
        if not isinstance(scalar, int): raise TypeError("FixedPoint can only multiply by int")
        return FixedPoint(self._value * scalar)
    def __floordiv__(self, divisor: int):
        if not isinstance(divisor, int): raise TypeError("FixedPoint can only divide by int")
        return FixedPoint(self._value // divisor)
    def __eq__(self, other): return self._value == other._value if isinstance(other, FixedPoint) else NotImplemented
    def __lt__(self, other): return self._value < other._value
    def __le__(self, other): return self._value <= other._value
    def __gt__(self, other): return self._value > other._value
    def __ge__(self, other): return self._value >= other._value
    def __repr__(self):
        sign = '-' if self._value < 0 else ''
        abs_val = abs(self._value)
        return f"FixedPoint({sign}{abs_val // self.SCALE}.{abs_val % self.SCALE:04d})"
    def __hash__(self): return hash(self._value)


@dataclass
class OrderEvent:
    msg_type: MessageType
    order_id: int
    side: Side
    price_fixed: FixedPoint
    quantity: int
    timestamp_ns: int


MESSAGE_SIZE = 26
MESSAGE_FORMAT = '>BQBiIQ'


class SimulatedWire:
    def __init__(self, messages: List[bytes]):
        self._buffer = b''.join(messages)
        self._offset = 0
        self._bytes_per_ns = 1.25

    def has_data(self) -> bool:
        return self._offset < len(self._buffer)

    def read_message(self) -> Tuple[bytes, int]:
        if not self.has_data():
            raise StopIteration("No more data on wire")
        raw = self._buffer[self._offset:self._offset + MESSAGE_SIZE]
        arrival_ns = int(self._offset / self._bytes_per_ns)
        self._offset += MESSAGE_SIZE
        return raw, arrival_ns

    def total_messages(self) -> int:
        return len(self._buffer) // MESSAGE_SIZE


def encode_message(msg_type, order_id, side, price_fixed, quantity, timestamp_ns):
    return struct.pack(MESSAGE_FORMAT, msg_type, order_id, side,
                       price_fixed, quantity, timestamp_ns)


class FeedDecoder:
    SIMULATED_DECODE_NS = 30

    def __init__(self):
        self.messages_decoded = 0
        self.total_decode_cycles = 0
        self.decode_errors = 0
        self._latencies = []

    def decode_message(self, raw_bytes: bytes) -> Optional[OrderEvent]:
        try:
            if len(raw_bytes) != MESSAGE_SIZE:
                self.decode_errors += 1
                return None

            msg_type_raw, order_id, side_raw, price_int, quantity, timestamp_ns = \
                struct.unpack(MESSAGE_FORMAT, raw_bytes)

            try:
                msg_type = MessageType(msg_type_raw)
            except ValueError:
                self.decode_errors += 1
                return None

            try:
                side = Side(side_raw)
            except ValueError:
                self.decode_errors += 1
                return None

            price_fixed = FixedPoint(price_int)

            event = OrderEvent(
                msg_type=msg_type,
                order_id=order_id,
                side=side,
                price_fixed=price_fixed,
                quantity=quantity,
                timestamp_ns=timestamp_ns
            )

            self.messages_decoded += 1
            self.total_decode_cycles += self.SIMULATED_DECODE_NS
            self._latencies.append(self.SIMULATED_DECODE_NS)

            return event

        except struct.error:
            self.decode_errors += 1
            return None

    def decode_stream(self, wire: SimulatedWire) -> List[OrderEvent]:
        events = []
        while wire.has_data():
            raw_bytes, arrival_ns = wire.read_message()
            event = self.decode_message(raw_bytes)
            if event is not None:
                events.append(event)
        return events

    def average_decode_ns(self) -> int:
        if not self._latencies:
            return 0
        return sum(self._latencies) // len(self._latencies)

    def get_latency_histogram(self) -> dict:
        histogram = {}
        for lat in self._latencies:
            bucket = (lat // 10) * 10
            histogram[bucket] = histogram.get(bucket, 0) + 1
        return histogram

from dataclasses import dataclass, field
from typing import List, Optional, Dict, Tuple

NUM_PRICE_LEVELS = 256

@dataclass
class Order:
    order_id: int
    side: Side
    price_fixed: FixedPoint
    quantity: int
    timestamp_ns: int

@dataclass
class PriceLevel:
    price: FixedPoint
    total_quantity: int = 0
    order_count: int = 0
    orders: List[Order] = field(default_factory=list)
    def is_empty(self) -> bool:
        return self.total_quantity == 0

@dataclass
class BookSnapshot:
    best_bid: Optional[FixedPoint]
    best_ask: Optional[FixedPoint]
    spread: Optional[FixedPoint]
    bid_depth: int
    ask_depth: int
    bid_levels: int
    ask_levels: int
    bid_vwap: Optional[FixedPoint]
    ask_vwap: Optional[FixedPoint]


class OrderBook:
    def __init__(self, reference_price: FixedPoint,
                 tick_size: FixedPoint = FixedPoint(100)):
        self.tick_size = tick_size
        self.reference_price = reference_price
        self.bid_base = FixedPoint(reference_price.value - NUM_PRICE_LEVELS * tick_size.value)
        self.ask_base = reference_price
        self.bid_levels = [
            PriceLevel(price=FixedPoint(self.bid_base.value + i * tick_size.value))
            for i in range(NUM_PRICE_LEVELS)
        ]
        self.ask_levels = [
            PriceLevel(price=FixedPoint(self.ask_base.value + i * tick_size.value))
            for i in range(NUM_PRICE_LEVELS)
        ]
        self._order_map: Dict[int, Tuple[Side, int]] = {}
        self.events_processed = 0

    def price_to_index(self, price: FixedPoint, side: Side) -> Optional[int]:
        if side == Side.BID:
            index = (price.value - self.bid_base.value) // self.tick_size.value
        else:
            index = (price.value - self.ask_base.value) // self.tick_size.value
        if index < 0 or index >= NUM_PRICE_LEVELS:
            return None
        return index

    def process_event(self, event: OrderEvent) -> bool:
        if event.msg_type == MessageType.ADD:
            ok = self._handle_add(event)
        elif event.msg_type == MessageType.MODIFY:
            ok = self._handle_modify(event)
        elif event.msg_type == MessageType.CANCEL:
            ok = self._handle_cancel(event)
        elif event.msg_type == MessageType.EXECUTE:
            ok = self._handle_execute(event)
        else:
            return False
        if ok:
            self.events_processed += 1
        return ok

    def _handle_add(self, event: OrderEvent) -> bool:
        idx = self.price_to_index(event.price_fixed, event.side)
        if idx is None:
            return False
        levels = self.bid_levels if event.side == Side.BID else self.ask_levels
        order = Order(event.order_id, event.side, event.price_fixed,
                      event.quantity, event.timestamp_ns)
        levels[idx].orders.append(order)
        levels[idx].total_quantity += event.quantity
        levels[idx].order_count += 1
        self._order_map[event.order_id] = (event.side, idx)
        return True

    def _handle_modify(self, event: OrderEvent) -> bool:
        if event.order_id not in self._order_map:
            return False
        side, idx = self._order_map[event.order_id]
        levels = self.bid_levels if side == Side.BID else self.ask_levels
        for order in levels[idx].orders:
            if order.order_id == event.order_id:
                levels[idx].total_quantity -= order.quantity
                levels[idx].total_quantity += event.quantity
                order.quantity = event.quantity
                return True
        return False

    def _handle_cancel(self, event: OrderEvent) -> bool:
        if event.order_id not in self._order_map:
            return False
        side, idx = self._order_map[event.order_id]
        levels = self.bid_levels if side == Side.BID else self.ask_levels
        for i, order in enumerate(levels[idx].orders):
            if order.order_id == event.order_id:
                levels[idx].total_quantity -= order.quantity
                levels[idx].order_count -= 1
                levels[idx].orders.pop(i)
                del self._order_map[event.order_id]
                return True
        return False

    def _handle_execute(self, event: OrderEvent) -> bool:
        if event.order_id not in self._order_map:
            return False
        side, idx = self._order_map[event.order_id]
        levels = self.bid_levels if side == Side.BID else self.ask_levels
        for i, order in enumerate(levels[idx].orders):
            if order.order_id == event.order_id:
                fill_qty = min(event.quantity, order.quantity)
                order.quantity -= fill_qty
                levels[idx].total_quantity -= fill_qty
                if order.quantity <= 0:
                    levels[idx].order_count -= 1
                    levels[idx].orders.pop(i)
                    del self._order_map[event.order_id]
                return True
        return False

    def get_best_bid(self) -> Optional[FixedPoint]:
        for i in range(NUM_PRICE_LEVELS - 1, -1, -1):
            if not self.bid_levels[i].is_empty():
                return self.bid_levels[i].price
        return None

    def get_best_ask(self) -> Optional[FixedPoint]:
        for i in range(NUM_PRICE_LEVELS):
            if not self.ask_levels[i].is_empty():
                return self.ask_levels[i].price
        return None

    def compute_vwap(self, side: Side, depth: int = 0) -> Optional[FixedPoint]:
        levels = self.bid_levels if side == Side.BID else self.ask_levels
        numerator = 0
        denominator = 0
        counted = 0
        if side == Side.BID:
            indices = range(NUM_PRICE_LEVELS - 1, -1, -1)
        else:
            indices = range(NUM_PRICE_LEVELS)
        for i in indices:
            if not levels[i].is_empty():
                numerator += levels[i].price.value * levels[i].total_quantity
                denominator += levels[i].total_quantity
                counted += 1
                if depth > 0 and counted >= depth:
                    break
        if denominator == 0:
            return None
        return FixedPoint(numerator // denominator)

    def snapshot(self) -> BookSnapshot:
        best_bid = self.get_best_bid()
        best_ask = self.get_best_ask()
        spread = None
        if best_bid is not None and best_ask is not None:
            spread = best_ask - best_bid
        bid_depth = sum(lv.total_quantity for lv in self.bid_levels)
        ask_depth = sum(lv.total_quantity for lv in self.ask_levels)
        bid_lv_count = sum(1 for lv in self.bid_levels if not lv.is_empty())
        ask_lv_count = sum(1 for lv in self.ask_levels if not lv.is_empty())
        bid_vwap = self.compute_vwap(Side.BID)
        ask_vwap = self.compute_vwap(Side.ASK)
        return BookSnapshot(
            best_bid=best_bid, best_ask=best_ask, spread=spread,
            bid_depth=bid_depth, ask_depth=ask_depth,
            bid_levels=bid_lv_count, ask_levels=ask_lv_count,
            bid_vwap=bid_vwap, ask_vwap=ask_vwap
        )

from dataclasses import dataclass, field
from typing import List, Optional, Tuple

@dataclass
class StrategyConfig:
    base_spread_bps: int = 10
    max_position: int = 1000
    skew_factor_bps: int = 1
    min_quote_size: int = 50
    max_quote_size: int = 500
    position_limit: int = 2000

@dataclass
class QuoteOrder:
    side: Side
    price_fixed: FixedPoint
    quantity: int

@dataclass
class QuotePair:
    bid: Optional[QuoteOrder]
    ask: Optional[QuoteOrder]
    mid_price: FixedPoint
    bid_spread_bps: int
    ask_spread_bps: int
    reason: str

@dataclass
class Fill:
    side: Side
    price_fixed: FixedPoint
    quantity: int
    timestamp_ns: int


class PositionTracker:
    def __init__(self):
        self.net_position = 0
        self.cash_fp = 0
        self.total_bought = 0
        self.total_sold = 0
        self.trade_count = 0
        self.fills = []

    def record_fill(self, fill: Fill) -> None:
        if fill.side == Side.BID:
            self.net_position += fill.quantity
            self.cash_fp -= fill.price_fixed.value * fill.quantity
            self.total_bought += fill.quantity
        else:
            self.net_position -= fill.quantity
            self.cash_fp += fill.price_fixed.value * fill.quantity
            self.total_sold += fill.quantity
        self.trade_count += 1
        self.fills.append(fill)

    def realized_pnl_fp(self) -> int:
        return self.cash_fp

    def unrealized_pnl_fp(self, current_price: FixedPoint) -> int:
        return self.net_position * current_price.value

    def total_pnl_fp(self, current_price: FixedPoint) -> int:
        return self.realized_pnl_fp() + self.unrealized_pnl_fp(current_price)

    def pnl_dollars(self, current_price: FixedPoint) -> float:
        return self.total_pnl_fp(current_price) / FixedPoint.SCALE


class TradingStrategy:
    def __init__(self, config: StrategyConfig):
        self.config = config
        self.position = PositionTracker()
        self.quotes_generated = 0
        self.quotes_suppressed = 0

    def compute_mid_price(self, best_bid: FixedPoint,
                          best_ask: FixedPoint) -> FixedPoint:
        return FixedPoint((best_bid.value + best_ask.value) // 2)

    def compute_spread_bps(self) -> Tuple[int, int]:
        pos = self.position.net_position
        bid_spread = self.config.base_spread_bps
        ask_spread = self.config.base_spread_bps
        if pos > 0:
            skew = abs(pos) * self.config.skew_factor_bps
            bid_spread += skew
            ask_spread -= skew
        elif pos < 0:
            skew = abs(pos) * self.config.skew_factor_bps
            bid_spread -= skew
            ask_spread += skew
        bid_spread = max(bid_spread, 1)
        ask_spread = max(ask_spread, 1)
        return bid_spread, ask_spread

    def bps_to_price_offset(self, mid_price: FixedPoint, bps: int) -> int:
        return mid_price.value * bps // 10000

    def compute_quote_size(self) -> int:
        remaining = self.config.max_position - abs(self.position.net_position)
        return min(self.config.max_quote_size, max(self.config.min_quote_size, remaining))

    def on_book_update(self, snapshot: BookSnapshot) -> Optional[QuotePair]:
        if snapshot.best_bid is None or snapshot.best_ask is None:
            self.quotes_suppressed += 1
            return None
        if abs(self.position.net_position) >= self.config.position_limit:
            self.quotes_suppressed += 1
            return None
        mid = self.compute_mid_price(snapshot.best_bid, snapshot.best_ask)
        bid_bps, ask_bps = self.compute_spread_bps()
        bid_offset = self.bps_to_price_offset(mid, bid_bps)
        ask_offset = self.bps_to_price_offset(mid, ask_bps)
        bid_price = FixedPoint(mid.value - bid_offset)
        ask_price = FixedPoint(mid.value + ask_offset)
        qty = self.compute_quote_size()
        bid_order = QuoteOrder(Side.BID, bid_price, qty)
        ask_order = QuoteOrder(Side.ASK, ask_price, qty)
        self.quotes_generated += 1
        return QuotePair(
            bid=bid_order, ask=ask_order, mid_price=mid,
            bid_spread_bps=bid_bps, ask_spread_bps=ask_bps,
            reason=f"pos={self.position.net_position} bid_bps={bid_bps} ask_bps={ask_bps}"
        )

    def on_fill(self, fill: Fill) -> None:
        self.position.record_fill(fill)

from dataclasses import dataclass, field
from typing import List, Optional, Dict, Tuple
from enum import Enum
import struct

class RiskRejectReason(Enum):
    POSITION_LIMIT = "position_limit_breached"
    RATE_LIMIT = "order_rate_exceeded"
    PRICE_DEVIATION = "price_too_far_from_mid"
    NOTIONAL_LIMIT = "notional_value_exceeded"
    INVALID_QUANTITY = "invalid_quantity"

@dataclass
class RiskLimits:
    max_position: int = 5000
    max_orders_per_second: int = 1000
    max_price_deviation_bps: int = 100
    max_notional: int = 10000000000
    min_quantity: int = 1
    max_quantity: int = 10000

@dataclass
class RiskCheckResult:
    approved: bool
    reject_reason: Optional[RiskRejectReason] = None
    details: str = ""


class RiskChecker:
    SIMULATED_CHECK_NS = 15

    def __init__(self, limits: RiskLimits):
        self.limits = limits
        self.orders_approved = 0
        self.orders_rejected = 0
        self.rejections_by_reason = {}
        self._order_timestamps_ns = []

    def check_order(self, order: QuoteOrder, current_position: int,
                    mid_price: FixedPoint, timestamp_ns: int) -> RiskCheckResult:
        # Check quantity validity
        if order.quantity < self.limits.min_quantity or order.quantity > self.limits.max_quantity:
            return self._record_rejection(
                RiskRejectReason.INVALID_QUANTITY,
                f"qty={order.quantity} outside [{self.limits.min_quantity}, {self.limits.max_quantity}]"
            )

        # Check position limit
        signed_qty = order.quantity if order.side == Side.BID else -order.quantity
        new_position = current_position + signed_qty
        if abs(new_position) > self.limits.max_position:
            return self._record_rejection(
                RiskRejectReason.POSITION_LIMIT,
                f"new_pos={new_position} exceeds limit={self.limits.max_position}"
            )

        # Check rate limit
        cutoff = timestamp_ns - 1_000_000_000
        self._order_timestamps_ns = [t for t in self._order_timestamps_ns if t > cutoff]
        if len(self._order_timestamps_ns) >= self.limits.max_orders_per_second:
            return self._record_rejection(
                RiskRejectReason.RATE_LIMIT,
                f"rate={len(self._order_timestamps_ns)}/s exceeds limit={self.limits.max_orders_per_second}"
            )

        # Check price deviation
        if mid_price.value != 0:
            deviation_bps = abs(order.price_fixed.value - mid_price.value) * 10000 // mid_price.value
            if deviation_bps > self.limits.max_price_deviation_bps:
                return self._record_rejection(
                    RiskRejectReason.PRICE_DEVIATION,
                    f"deviation={deviation_bps}bps exceeds limit={self.limits.max_price_deviation_bps}bps"
                )

        # Check notional limit
        notional = order.price_fixed.value * order.quantity
        if notional > self.limits.max_notional:
            return self._record_rejection(
                RiskRejectReason.NOTIONAL_LIMIT,
                f"notional={notional} exceeds limit={self.limits.max_notional}"
            )

        # All checks passed
        self.orders_approved += 1
        self._order_timestamps_ns.append(timestamp_ns)
        return RiskCheckResult(approved=True)

    def _record_rejection(self, reason, details):
        self.orders_rejected += 1
        self.rejections_by_reason[reason] = self.rejections_by_reason.get(reason, 0) + 1
        return RiskCheckResult(approved=False, reject_reason=reason, details=details)


OUTBOUND_FORMAT = '>BQBiIQ'
OUTBOUND_SIZE = 26


class OrderEncoder:
    SIMULATED_ENCODE_NS = 10

    def __init__(self):
        self.messages_encoded = 0

    def encode_order(self, order: QuoteOrder, order_id: int,
                     timestamp_ns: int) -> bytes:
        self.messages_encoded += 1
        return struct.pack(OUTBOUND_FORMAT, MessageType.ADD, order_id,
                           order.side, order.price_fixed.value,
                           order.quantity, timestamp_ns)


@dataclass
class PipelineStage:
    name: str
    budget_ns: int
    actual_ns: int = 0
    within_budget: bool = True

@dataclass
class LatencyReport:
    stages: List[PipelineStage]
    total_budget_ns: int
    total_actual_ns: int
    within_budget: bool
    def __repr__(self):
        lines = ["\n=== Tick-to-Trade Latency Report ==="]
        lines.append(f"{'Stage':<20} {'Budget':>8} {'Actual':>8} {'Status':>8}")
        lines.append("-" * 48)
        for s in self.stages:
            status = "OK" if s.within_budget else "OVER"
            lines.append(f"{s.name:<20} {s.budget_ns:>6}ns {s.actual_ns:>6}ns {status:>8}")
        lines.append("-" * 48)
        status = "PASS" if self.within_budget else "FAIL"
        lines.append(f"{'TOTAL':<20} {self.total_budget_ns:>6}ns {self.total_actual_ns:>6}ns {status:>8}")
        return "\n".join(lines)


class LatencyAnalyzer:
    STAGE_BUDGETS = {
        "nic_receive": 50, "feed_decode": 30, "book_update": 20,
        "strategy": 40, "risk_check": 15, "order_encode": 10,
        "nic_transmit": 50,
    }

    def __init__(self):
        self._tick_stages = []
        self._all_reports = []

    def start_tick(self):
        self._tick_stages = []

    def record_stage(self, stage_name: str, actual_ns: int):
        budget = self.STAGE_BUDGETS.get(stage_name, 0)
        self._tick_stages.append(PipelineStage(
            name=stage_name, budget_ns=budget,
            actual_ns=actual_ns, within_budget=(actual_ns <= budget)
        ))

    def finish_tick(self) -> LatencyReport:
        total_budget = sum(s.budget_ns for s in self._tick_stages)
        total_actual = sum(s.actual_ns for s in self._tick_stages)
        report = LatencyReport(
            stages=list(self._tick_stages),
            total_budget_ns=total_budget,
            total_actual_ns=total_actual,
            within_budget=(total_actual <= total_budget)
        )
        self._all_reports.append(report)
        return report

    def summary(self):
        if not self._all_reports:
            return {"ticks": 0}
        totals = [r.total_actual_ns for r in self._all_reports]
        return {
            "ticks": len(totals),
            "avg_ns": sum(totals) // len(totals),
            "min_ns": min(totals),
            "max_ns": max(totals),
            "within_budget_pct": sum(1 for r in self._all_reports if r.within_budget) * 100 // len(self._all_reports),
        }


class PipelineSimulator:
    def __init__(self, reference_price: FixedPoint,
                 strategy_config: StrategyConfig,
                 risk_limits: RiskLimits):
        self.decoder = FeedDecoder()
        self.book = OrderBook(reference_price)
        self.strategy = TradingStrategy(strategy_config)
        self.risk_checker = RiskChecker(risk_limits)
        self.encoder = OrderEncoder()
        self.latency = LatencyAnalyzer()
        self._next_order_id = 1000000
        self.ticks_processed = 0
        self.orders_sent = 0

    def process_tick(self, raw_message: bytes, arrival_ns: int) -> Optional[LatencyReport]:
        self.latency.start_tick()

        # Stage 1: NIC Receive
        self.latency.record_stage("nic_receive", 50)

        # Stage 2: Feed Decode
        event = self.decoder.decode_message(raw_message)
        self.latency.record_stage("feed_decode", FeedDecoder.SIMULATED_DECODE_NS)
        if event is None:
            return self.latency.finish_tick()

        # Stage 3: Book Update
        self.book.process_event(event)
        self.latency.record_stage("book_update", 20)

        # Stage 4: Strategy
        snap = self.book.snapshot()
        quotes = self.strategy.on_book_update(snap)
        self.latency.record_stage("strategy", 40)
        if quotes is None:
            return self.latency.finish_tick()

        # Stage 5: Risk Check
        mid = quotes.mid_price
        cur_pos = self.strategy.position.net_position
        approved_orders = []
        if quotes.bid is not None:
            result = self.risk_checker.check_order(quotes.bid, cur_pos, mid, arrival_ns)
            if result.approved:
                approved_orders.append(quotes.bid)
        if quotes.ask is not None:
            result = self.risk_checker.check_order(quotes.ask, cur_pos, mid, arrival_ns)
            if result.approved:
                approved_orders.append(quotes.ask)
        self.latency.record_stage("risk_check", RiskChecker.SIMULATED_CHECK_NS)

        # Stage 6: Order Encode
        for order in approved_orders:
            self.encoder.encode_order(order, self._next_order_id, arrival_ns)
            self._next_order_id += 1
            self.orders_sent += 1
        self.latency.record_stage("order_encode", OrderEncoder.SIMULATED_ENCODE_NS)

        # Stage 7: NIC Transmit
        self.latency.record_stage("nic_transmit", 50)

        self.ticks_processed += 1
        return self.latency.finish_tick()
